const _debug=(message)=>{};export class QuickActions{static actions=[{id: 'new-lead',label: 'Thêm Lead mới',icon: 'person_add',shortcut: 'Ctrl+Shift+L',action:()=>window.location.href='/admin/leads.html?action=new',category: 'common'},{id: 'new-campaign',label: 'Chiến dịch mới',icon: 'campaign',shortcut: 'Ctrl+Shift+C',action:()=>window.location.href='/admin/campaigns.html?action=new',category: 'common'},{id: 'new-task',label: 'Task mới',icon: 'add_task',shortcut: 'Ctrl+Shift+T',action:()=>QuickActions.openTaskModal(),category: 'common'},{id: 'export-data',label: 'Xuất dữ liệu',icon: 'download',shortcut: 'Ctrl+Shift+E',action:()=>QuickActions.exportData(),category: 'data'},{id: 'refresh',label: 'Làm mới',icon: 'refresh',shortcut: 'Ctrl+R',action:()=>window.location.reload(),category: 'navigation'},{id: 'search',label: 'Tìm kiếm',icon: 'search',shortcut: 'Ctrl+K',action:()=>{const event=new KeyboardEvent('keydown',{key: 'k',ctrlKey: true});document.dispatchEvent(event);},category: 'navigation'},{id: 'settings',label: 'Cài đặt',icon: 'settings',shortcut: 'Ctrl+Shift+S',action:()=>QuickActions.openSettings(),category: 'settings'},{id: 'help',label: 'Trợ giúp',icon: 'help',shortcut: 'F1',action:()=>QuickActions.openHelp(),category: 'settings'}];static init(){this.createFAB();this.bindKeyboard();_debug('[QuickActions] Initialized');}static createFAB(){const existing=document.querySelector('.quick-actions-fab');if(existing)existing.remove();const fab=document.createElement('div');fab.className='quick-actions-fab';fab.innerHTML=`<button class="fab-button" aria-label="Quick Actions" aria-expanded="false"><span class="material-symbols-outlined">add</span></button><div class="quick-actions-menu" role="menu" aria-hidden="true"><div class="quick-actions-search"><span class="material-symbols-outlined">search</span><input type="text" placeholder="Search actions..." class="quick-actions-input"/></div><div class="quick-actions-list"></div></div>`;document.body.appendChild(fab);this.bindFABEvents(fab);}static bindFABEvents(fab){const button=fab.querySelector('.fab-button');const menu=fab.querySelector('.quick-actions-menu');const input=fab.querySelector('.quick-actions-input');const list=fab.querySelector('.quick-actions-list');button.addEventListener('click',(e)=>{e.stopPropagation();const isOpen=menu.classList.toggle('visible');button.setAttribute('aria-expanded',isOpen);menu.setAttribute('aria-hidden',!isOpen);if(isOpen){this.populateMenu(list);setTimeout(()=>input.focus(),100);}});document.addEventListener('click',(e)=>{if(!fab.contains(e.target)){menu.classList.remove('visible');button.setAttribute('aria-expanded','false');menu.setAttribute('aria-hidden','true');}});input.addEventListener('input',(e)=>{const query=e.target.value.toLowerCase();this.filterActions(list,query);});input.addEventListener('keydown',(e)=>{if(e.key==='Escape'){menu.classList.remove('visible');button.focus();}});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&menu.classList.contains('visible')){menu.classList.remove('visible');button.focus();}});}static populateMenu(container){container.innerHTML='';const categories={};this.actions.forEach(action=>{if(!categories[action.category]){categories[action.category]=[];}categories[action.category].push(action);});Object.entries(categories).forEach(([category,actions])=>{const section=document.createElement('div');section.className='quick-actions-section';const title=document.createElement('div');title.className='quick-actions-category';title.textContent=this.getCategoryName(category);section.appendChild(title);actions.forEach(action=>{const item=document.createElement('div');item.className='quick-action-item';item.setAttribute('role','menuitem');item.innerHTML=`<span class="material-symbols-outlined">${action.icon}</span><span class="action-label">${action.label}</span><kbd class="action-shortcut">${action.shortcut}</kbd>`;item.addEventListener('click',()=>{action.action();this.closeMenu();});section.appendChild(item);});container.appendChild(section);});}static filterActions(container,query){const items=container.querySelectorAll('.quick-action-item');items.forEach(item=>{const label=item.querySelector('.action-label').textContent.toLowerCase();const matches=label.includes(query);item.style.display=matches ? '' : 'none';});}static getCategoryName(category){const names={common: 'Phổ biến',data: 'Dữ liệu',navigation: 'Điều hướng',settings: 'Cài đặt'};return names[category]||category;}static closeMenu(){const menu=document.querySelector('.quick-actions-menu');const button=document.querySelector('.fab-button');if(menu){menu.classList.remove('visible');button?.setAttribute('aria-expanded','false');}}static bindKeyboard(){document.addEventListener('keydown',(e)=>{if(e.ctrlKey&&e.shiftKey&&e.key==='A'){e.preventDefault();const fab=document.querySelector('.fab-button');fab?.click();}});}static openTaskModal(){const Toast=window.SadecToast||window.Toast;Toast?.info('Tính năng task đang được phát triển...');}static exportData(){const ExportManager=window.ExportManager;const Toast=window.SadecToast||window.Toast;Toast?.info('Đang chuẩn bị xuất dữ liệu...');if(ExportManager){const sampleData=[{id: 1,name: 'Lead 1',status: 'new',value: 1000},{id: 2,name: 'Lead 2',status: 'contacted',value: 2500},{id: 3,name: 'Lead 3',status: 'converted',value: 5000}];ExportManager.toCSV(sampleData,'leads-export.csv');}}static openSettings(){const UserPreferences=window.UserPreferences;if(UserPreferences){UserPreferences.showPanel();}}static openHelp(){window.open('https://sadecmarketinghub.com/docs','_blank');}static addAction(action){this.actions.push(action);}static removeAction(id){this.actions=this.actions.filter(a=>a.id!==id);}}if(typeof document!=='undefined'){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>QuickActions.init());}else{QuickActions.init();}}export default QuickActions;if(typeof window!=='undefined'){window.QuickActions=QuickActions;}